FROM support_agents 
ORDER BY name;

SELECT name 
FROM customers 
ORDER BY name;

SELECT question 
FROM knowledge_base 
WHERE view_count = (SELECT MAX(view_count) FROM knowledge_base);

SELECT question, view_count
FROM knowledge_base
ORDER BY view_count DESC;
